INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 0, 1, "ヒヨリでっす♪\n元気いっぱいがんばるよ♪", 1, 1, 0, 0, "春咲 ひより", "お！\nあそこに困ってそうな人発見！", 1001, "ねぇねぇ、騎士クン\n手伝ってあげようよ～", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 0, 1, "みんなみたいに\nわたしも強くならなきゃ", 1, 1, 0, 0, "草野 優衣", "大切な人を\n守れるようになりたい…って", 1002, "わ、わたし、\nなに言ってるんだろ\nあはは…", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 0, 1, "フェンシングを始めてみては？", 1, 1, 0, 0, "士条 怜", "キミに必要な集中力と感性が", 1003, "少しは磨かれると思いますよ。", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 0, 1, "ねぇ、にいちゃん！", 1, 1, 0, 0, "穂高 みそぎ", "今日はなにして遊ぶ？", 1004, "みそぎはねぇ、\nかくれんぼやりたい！", 1.5, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 0, 1, "風宮あかりです", 1, 1, 0, 0, "風宮 あかり", "ねぇ…", 1006, "私といっしょに…\nいかない？", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 0, 1, "出雲宮子なのー", 1, 1, 0, 0, "出雲 宮子", "プリンたべたいのー", 1007, "食べ物の恨みは怖いのー", 1.5, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 0, 1, "ボクは虹村雪。", 1, 1, 0, 0, "虹村 雪", "キミもボクの美貌に\n吸い寄せられたんだね。", 1008, "いいよ。\n見られることは運命さ…", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 0, 1, "フッ…聞いて後悔するがいい！", 1, 1, 0, 0, "柊杏奈", "我が真名は\nアンネローゼ・フォン・シュテッヒパルム！", 1009, "人呼んで「疾風の冥姫」!!", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 0, 1, "マホマホ王国のプリンセス、\nまほ姫どす", 1, 1, 0, 0, "姫宮 真歩", "うさぎさん、\n運命の王子はんに巡りあわせてくれて", 1010, "ほんまおおきにやわ～♪", 1.5, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 0, 1, "衣之咲璃乃です！", 1, 1, 0, 0, "衣之咲 璃乃", "生き別れたお兄ちゃんを探して\n三千世界！", 1011, "ここで会ったが\n100年目～！", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 0, 1, "私はハツネ、\n結構強いんだよ。\nきらーん☆", 1, 1, 0, 0, "柏崎 初音", "ち、超能力って…\n何のことかな～？", 1012, "…って、お願い！\n誰にも言わないでおいて～！", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 0, 1, "ちょす！\n美波鈴奈だよ～♪", 1, 1, 0, 0, "美波 鈴奈", "一応カリスマ読モJKやってまっす！", 1016, "ヒデサイまぢ\nGF（グッドフィーリング）～♪", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 0, 1, "はいたーい。\n喜屋武香織さー。", 1, 1, 0, 0, "喜屋武 香織", "東京は遊園地みたいなところさー", 1017, "でも、沖縄もとってもいいとこさー", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 0, 1, "支倉伊緒です。", 1, 1, 0, 0, "支倉 伊緒", "先生って呼ばれるのは\nくすぐったいから", 1018, "イオちゃんって呼んでね。", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 0, 1, "ふえ…？\nミミ、むずかしいこと\nよくわかんない…", 1, 1, 0, 0, "茜 ミミ", "あ！/\お兄ちゃ～ん\nまってよ～", 1020, "ミミをおいてかないでぇ～", 1.5, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 0, 1, "あ…あの…えっと…\n栗…林…くるみ…です……", 1, 1, 0, 0, "栗林 くるみ", "あの……\nふぇ……", 1021, "ふぇぇぇぇぇん……", 1.5, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 0, 1, "風宮よりです。\nあああああ！", 1, 1, 0, 0, "風宮 より", "こんな私に貴重な時間を\n割いていただき、", 1022, "なんてありがとうございます！", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 0, 1, "私、アヤネ！\nぷうきちと一緒についてってあげるね！", 1, 1, 0, 0, "北条 綾音", "おにいちゃんどこいくの？\nえ？", 1023, "私こっち行きたいー\nね、早く早くー", 1.5, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 0, 1, "わっ…わっ…私、\n天野すずめといいます！", 1, 1, 0, 0, "天野 すずめ", "ふ、不束者ですが\nどうぞ末永く…って、", 1025, "これて何か違う…\nあああすみません！", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 0, 1, "……クスクス…私は\n…倉石恵理子……", 1, 1, 0, 0, "倉石 恵理子", "あなたは…運命の……\n伴侶……", 1027, "離しませんわ………\n絶対に…!!", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 0, 1, "佐々木咲恋よ。\nねえ、世の中に無駄なことが\n多すぎると思わない？", 1, 1, 0, 0, "佐々木 咲恋", "その無駄を省くことができれば、\nもっと余裕のある暮らしができるっ！", 1028, "…そうでしょ？？", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 0, 1, "桜井望だよ！\nよろしくねっ", 1, 1, 0, 0, "桜井 望", "ぇっと…\nキミ、私のこと知らないの?!", 1029, "あはは、\n私もまだまだだなぁ～", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 0, 1, "デケデケデンっ！", 1, 1, 0, 0, "ニノン・ジュベール", "初めまして、\n私はニノン・ジュベール申すデス！", 1030, "ショーグン、\nワタシと一緒に天下統一デース！", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 0, 1, "上喜しのぶです。\n手元のドクロが父です。", 1, 1, 0, 0, "上喜 しのぶ", "でもって私の隣にいるのが……\nえ、見えない？", 1031, "おかしいですね……", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 0, 1, "目指すはビッグな\nお笑い芸人だっぺ！", 1, 1, 0, 0, "野戸まひる", "けんども\nそれには足りないモンが…", 1033, "そう、\nオラのボケに突っ込める相方が…！", 1.5, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 0, 1, "あの…私…綾瀬ゆかりです…\nあの…ごめんなさい！", 1, 1, 0, 0, "綾瀬 ゆかり", "ちょっと緊張しちゃって…", 1034, "ちょ\nちょっと一杯飲んできます…！", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 0, 1, "氷川鏡華…です", 1, 1, 0, 0, "氷川 鏡華", "知らない人とは話しちゃいけないので", 1036, "これ以上お話しすることは…\nないです！", 1.5, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 0, 1, "柏崎…栞です。", 1, 1, 0, 0, "柏崎 栞", "……あ、アラーム。", 1038, "私体が弱いから、\n30分に一度休憩しないと\nいけないんです。", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 0, 1, "ふ、双葉碧です。", 1, 1, 0, 0, "双葉 碧", "私、一人も友達がいなくて……", 1040, "野に咲く花が、\n唯一の話相手です。", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 0, 1, "三角千歌です。", 1, 1, 0, 0, "三角 千歌", "私の歌声で、\n皆さんが幸せになってくれたらいいなって…", 1042, "そう思っています。", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 0, 1, "安芸真琴だ。", 1, 1, 0, 0, "安芸 真琴", "あぁ？\nお前のそいつの仲間か？", 1043, "う、疑ってすまなかったな…", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 0, 1, "わらわこそは夜を総べる者！", 1, 1, 0, 0, "イリヤ・オーンスタイン", "生けとし生ける全ての者よ！", 1044, "わらわの偉大な力に\nひれ伏すがいい！\nはっはっは！", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 0, 1, "そこで騎士は妖精を乱暴に……", 1, 1, 0, 0, "遠見 空花", "ぐふふふふ……はっ！", 1045, "ｌク、クウカに何かご用ですか!?", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 0, 1, "宮坂たまきにゃ♪\n猫はいいにゃよ？", 1, 1, 0, 0, "宮坂たまき", "自由気ままで♪\n寝て遊んで、食べてケンカして…", 1046, "う～ん…\n猫ってホントに最高にゃ～♪", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 0, 1, "大神美冬よ！", 1, 1, 0, 0, "大神 美冬", "それでは早速クエストに…", 1048, "…と思ったら\nバイトの時間だ！\nまたあとでね！", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 0, 1, "星野静流だよ！", 1, 1, 0, 0, "星野静流", "クエストもバトルも\n掃除も洗濯も", 1049, "お姉ちゃんがぜ～んぶ\nやってあげるからね！", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 0, 1, "アタシは玉泉美咲。", 1, 1, 0, 0, "玉泉美咲", "見ての通りの\nセクシー美少女で", 1050, "学校では誰もが憧れる\nアイドル的な存在ってやつよ♪", 1.5, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 0, 1, "？？？", 1, 1, 0, 0, "リマ", "？？？？", 1052, "？？？？", 1.4, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 0, 1, "モニカ・ヴァイスヴィントだ。", 1, 1, 0, 0, "モニカ・ヴァイスヴィント", "菓子でつろうなどと\n稚拙な策を……", 1053, "そ、そこまでいうなら\nもらってやる", 1.5, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 0, 1, "モニカ・ヴァイスヴィントだ。", 1, 1, 0, 0, "ペコリーヌ", "菓子でつろうなどと\n稚拙な策を……", 1058, "そ、そこまでいうなら\nもらってやる", 1.5, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 0, 1, "モニカ・ヴァイスヴィントだ。", 1, 1, 0, 0, "コッコロ", "菓子でつろうなどと\n稚拙な策を……", 1059, "そ、そこまでいうなら\nもらってやる", 1.5, 0, 2);
INSERT INTO `v1_e5f13eca5fd1fca1555b347b646cb426d7cc39f65be6d4f221e6e6a503b5adcc` VALUES (0, 0, 1, "モニカ・ヴァイスヴィントだ。", 1, 1, 0, 0, "キャル", "菓子でつろうなどと\n稚拙な策を……", 1060, "そ、そこまでいうなら\nもらってやる", 1.5, 0, 2);
